const MONTHS = D.months;
const N = MONTHS.length;

/* ---------- design tokens ---------- */
const T = {
  ink: "#171b26",
  canvas: "#f3f4f6",
  surface: "#ffffff",
  subtle: "#fafbfc",
  border: "#e5e7eb",
  muted: "#6b7280",
  faint: "#9ca3af",
  primary: "#0f766e",
  primarySoft: "#d5efec",
  primaryInk: "#0b5850",
  up: "#15803d",
  down: "#dc2626",
};
/* Channel colour guideline — fixed, do not reassign */
const CH = {
  MarketPlace: { c: "#E24B76", s: "#FBE0E8", t: "MarketPlace" },
  Online: { c: "#E08A2B", s: "#FBEAD3", t: "Online" },
  Online_คุณอ้อย: { c: "#8A5CB8", s: "#EADFF4", t: "Online_คุณอ้อย" },
  "Online ขนมน้องRisa": { c: "#4E9A51", s: "#DEEEDF", t: "ขนมน้องRisa" },
  Telesale: { c: "#3B7DC4", s: "#DAE8F6", t: "Telesale" },
};
const chColor = (name) => (CH[name] ? CH[name].c : "#94a3b8");
const chSoft = (name) => (CH[name] ? CH[name].s : "#eef2f6");
/* neutral palette for non-channel categorical charts */
const PAL = [
  "#0f766e",
  "#3b6fb0",
  "#b06a2e",
  "#7a5aa8",
  "#4e9a51",
  "#c2537a",
  "#5a8fa8",
  "#9a7b3e",
  "#6b7280",
  "#8a6d9b",
  "#3f8c7f",
  "#a2557c",
];

const THMON = [
  "ม.ค.",
  "ก.พ.",
  "มี.ค.",
  "เม.ย.",
  "พ.ค.",
  "มิ.ย.",
  "ก.ค.",
  "ส.ค.",
  "ก.ย.",
  "ต.ค.",
  "พ.ย.",
  "ธ.ค.",
];
function monLabel(m) {
  const [y, mo] = m.split("-");
  return THMON[+mo - 1];
}
function monLabelY(m) {
  const [y, mo] = m.split("-");
  return THMON[+mo - 1] + " " + String(+y + 543).slice(-2);
}
function monLabelFull(i) {
  const m = MONTHS[i];
  const [y, mo] = m.split("-");
  return THMON[+mo - 1] + " " + (+y + 543);
}

/* ---------- number helpers ---------- */
const nf = new Intl.NumberFormat("th-TH");
function fi(n) {
  return nf.format(Math.round(n || 0));
}
function fc(n) {
  n = n || 0;
  return n >= 1e6
    ? (n / 1e6).toFixed(n >= 1e7 ? 0 : 1) + "M"
    : n >= 1e3
    ? (n / 1e3).toFixed(n >= 1e4 ? 0 : 1) + "K"
    : fi(n);
}
function fb(n) {
  return "฿" + fi(n);
}
function fbc(n) {
  return "฿" + fc(n);
}

/* sum a sparse {idx:val} object over inclusive month range [a,b] */
function sumRange(obj, a, b) {
  if (!obj) return 0;
  let s = 0;
  for (const k in obj) {
    const i = +k;
    if (i >= a && i <= b) s += obj[k];
  }
  return s;
}
/* array of monthly values across full axis */
function series(obj) {
  const out = new Array(N).fill(0);
  if (obj) for (const k in obj) out[+k] = obj[k];
  return out;
}

/* ---------- period presets ---------- */
const QUARTERS = [
  ["Q1/25", 0, 2],
  ["Q2/25", 3, 5],
  ["Q3/25", 6, 8],
  ["Q4/25", 9, 11],
  ["Q1/26", 12, 14],
  ["Q2/26", 15, 17],
];
const QUICK = [
  ["ทั้งหมด (18 เดือน)", 0, 17],
  ["12 เดือนล่าสุด", 6, 17],
  ["6 เดือนล่าสุด", 12, 17],
  ["3 เดือนล่าสุด", 15, 17],
  ["ปี 2025", 0, 11],
  ["ปี 2026 (ครึ่งปีแรก)", 12, 17],
];

function deltaPct(cur, prev) {
  if (prev === 0) return cur > 0 ? 100 : null;
  return ((cur - prev) / prev) * 100;
}
function Delta({ cur, prev, invert }) {
  if (prev == null) return null;
  const d = deltaPct(cur, prev);
  if (d == null) return <span style={{ fontSize: 11, color: T.faint }}>—</span>;
  const good = invert ? d < 0 : d >= 0;
  const col = good ? T.up : T.down;
  const arrow = d >= 0 ? "▲" : "▼";
  return (
    <span style={{ fontSize: 11, fontWeight: 700, color: col, marginLeft: 6 }}>
      {arrow} {Math.abs(d).toFixed(1)}%
    </span>
  );
}

/* =========================================================================
   PERIOD BAR
   ========================================================================= */
function PeriodBar({
  range,
  setRange,
  compare,
  setCompare,
  metricObj,
  cmpRange,
}) {
  const [from, to] = range;
  const monthsArr = series(metricObj);
  const maxV = Math.max(1, ...monthsArr);
  const isActive = (a, b) => a === from && b === to;

  const btn = (active) => ({
    padding: "6px 11px",
    fontSize: 12,
    borderRadius: 7,
    cursor: "pointer",
    border: "1px solid " + (active ? T.ink : T.border),
    background: active ? T.ink : T.surface,
    color: active ? "#fff" : T.muted,
    fontWeight: active ? 700 : 500,
    whiteSpace: "nowrap",
    transition: "all .12s",
  });

  return (
    <div
      style={{
        background: T.surface,
        border: "1px solid " + T.border,
        borderRadius: 12,
        padding: "14px 16px",
        marginBottom: 16,
      }}
    >
      {/* row 1: quick + quarters */}
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          gap: 7,
        }}
      >
        <span
          style={{
            fontSize: 12,
            fontWeight: 700,
            color: T.ink,
            marginRight: 4,
          }}
        >
          ช่วงเวลา
        </span>
        {QUICK.map(([lab, a, b]) => (
          <button
            key={lab}
            style={btn(isActive(a, b))}
            onClick={() => setRange([a, b])}
          >
            {lab}
          </button>
        ))}
        <span
          style={{
            width: 1,
            height: 20,
            background: T.border,
            margin: "0 3px",
          }}
        />
        <span style={{ fontSize: 12, fontWeight: 700, color: T.muted }}>
          ไตรมาส
        </span>
        {QUARTERS.map(([lab, a, b]) => (
          <button
            key={lab}
            style={btn(isActive(a, b))}
            onClick={() => setRange([a, b])}
          >
            {lab}
          </button>
        ))}
      </div>

      {/* row 2: custom range + compare + summary */}
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          gap: 8,
          marginTop: 11,
        }}
      >
        <span style={{ fontSize: 12, color: T.muted }}>จาก</span>
        <select
          value={from}
          onChange={(e) => {
            const v = +e.target.value;
            setRange([v, Math.max(v, to)]);
          }}
          style={selStyle}
        >
          {MONTHS.map((m, i) => (
            <option key={i} value={i}>
              {monLabelY(m)}
            </option>
          ))}
        </select>
        <span style={{ fontSize: 12, color: T.muted }}>ถึง</span>
        <select
          value={to}
          onChange={(e) => {
            const v = +e.target.value;
            setRange([Math.min(from, v), v]);
          }}
          style={selStyle}
        >
          {MONTHS.map((m, i) => (
            <option key={i} value={i} disabled={i < from}>
              {monLabelY(m)}
            </option>
          ))}
        </select>
        <button
          style={{ ...btn(false), color: T.muted }}
          onClick={() => setRange([0, 17])}
        >
          รีเซ็ต
        </button>

        <span
          style={{
            width: 1,
            height: 20,
            background: T.border,
            margin: "0 3px",
          }}
        />
        <span style={{ fontSize: 12, color: T.muted }}>เทียบกับ</span>
        {[
          ["ช่วงก่อนหน้า", "prev"],
          ["ปีก่อน", "yoy"],
          ["ไม่เทียบ", "none"],
        ].map(([lab, val]) => (
          <button
            key={val}
            style={btn(compare === val)}
            onClick={() => setCompare(val)}
          >
            {lab}
          </button>
        ))}

        <div style={{ marginLeft: "auto", textAlign: "right" }}>
          <div
            style={{
              fontSize: 13,
              fontWeight: 800,
              color: T.ink,
              letterSpacing: "-.2px",
            }}
          >
            {monLabelFull(from)} <span style={{ color: T.faint }}>→</span>{" "}
            {monLabelFull(to)}
          </div>
          <div style={{ fontSize: 11, color: T.faint }}>
            ({to - from + 1} เดือน) ·{" "}
            {compare === "none" || !cmpRange
              ? "ไม่มีช่วงเทียบ"
              : (compare === "prev" ? "เทียบช่วงก่อนหน้า" : "เทียบปีก่อน") +
                ": " +
                monLabelFull(cmpRange[0]) +
                " → " +
                monLabelFull(cmpRange[1])}
          </div>
        </div>
      </div>

      {/* row 3: month mini-bars */}
      <div style={{ marginTop: 12 }}>
        <div
          style={{
            display: "flex",
            gap: 0,
            position: "relative",
            borderTop: "1px solid " + T.border,
            paddingTop: 8,
          }}
        >
          {/* year band labels */}
        </div>
        <div
          style={{
            display: "flex",
            alignItems: "flex-end",
            gap: 3,
            height: 56,
          }}
        >
          {monthsArr.map((v, i) => {
            const inRange = i >= from && i <= to;
            const inCmp = cmpRange && i >= cmpRange[0] && i <= cmpRange[1];
            const h = Math.max(3, (v / maxV) * 52);
            return (
              <div
                key={i}
                title={monLabelFull(i) + ": " + fi(v)}
                onClick={() => {
                  // click a month to set as endpoint smartly
                  if (i < from) setRange([i, to]);
                  else setRange([from, i]);
                }}
                style={{
                  flex: 1,
                  display: "flex",
                  flexDirection: "column",
                  justifyContent: "flex-end",
                  cursor: "pointer",
                }}
              >
                <div
                  style={{
                    height: h,
                    borderRadius: "3px 3px 0 0",
                    background: inRange
                      ? T.primary
                      : inCmp
                      ? "#f0b8b8"
                      : "#e5e7eb",
                    outline:
                      inCmp && !inRange ? "1px dashed " + T.down : "none",
                  }}
                />
              </div>
            );
          })}
        </div>
        <div style={{ display: "flex", gap: 3, marginTop: 4 }}>
          {monthsArr.map((v, i) => (
            <div
              key={i}
              style={{
                flex: 1,
                textAlign: "center",
                fontSize: 9,
                color: i >= from && i <= to ? T.ink : T.faint,
                fontWeight: i >= from && i <= to ? 700 : 400,
              }}
            >
              {monLabel(MONTHS[i])}
            </div>
          ))}
        </div>
        <div style={{ display: "flex", marginTop: 2 }}>
          <div
            style={{
              flex: 12,
              textAlign: "center",
              fontSize: 10,
              color: T.faint,
              borderTop: "1px solid " + T.border,
              paddingTop: 2,
            }}
          >
            2025
          </div>
          <div
            style={{
              flex: 6,
              textAlign: "center",
              fontSize: 10,
              color: T.faint,
              borderTop: "1px solid " + T.border,
              paddingTop: 2,
              marginLeft: 3,
            }}
          >
            2026
          </div>
        </div>
      </div>
    </div>
  );
}
const selStyle = {
  fontSize: 12,
  padding: "6px 8px",
  borderRadius: 7,
  border: "1px solid " + T.border,
  background: T.surface,
  color: T.ink,
  cursor: "pointer",
  maxWidth: 150,
};

/* =========================================================================
   SMALL UI PARTS
   ========================================================================= */
function Kpi({ label, value, sub, delta, accent }) {
  return (
    <div
      style={{
        background: T.surface,
        border: "1px solid " + T.border,
        borderRadius: 11,
        padding: "14px 15px",
        borderLeft: "4px solid " + (accent || T.primary),
      }}
    >
      <div style={{ fontSize: 11, color: T.muted, marginBottom: 5 }}>
        {label}
      </div>
      <div
        style={{
          fontSize: 20,
          fontWeight: 800,
          color: T.ink,
          letterSpacing: "-.4px",
          lineHeight: 1,
        }}
      >
        {value}
        {delta}
      </div>
      {sub != null && (
        <div style={{ fontSize: 10.5, color: T.faint, marginTop: 4 }}>
          {sub}
        </div>
      )}
    </div>
  );
}
function Card({ title, hint, children, pad = 16 }) {
  return (
    <div
      style={{
        background: T.surface,
        border: "1px solid " + T.border,
        borderRadius: 12,
        padding: pad,
      }}
    >
      {title && (
        <div
          style={{
            display: "flex",
            alignItems: "baseline",
            justifyContent: "space-between",
            marginBottom: 12,
          }}
        >
          <h3
            style={{ margin: 0, fontSize: 14, fontWeight: 800, color: T.ink }}
          >
            {title}
          </h3>
          {hint && <span style={{ fontSize: 11, color: T.faint }}>{hint}</span>}
        </div>
      )}
      {children}
    </div>
  );
}
function TypeBadge({ t }) {
  const map = {
    ขาย: T.primary,
    Set: "#3b6fb0",
    ของแถม: "#b06a2e",
    Tester: "#c2537a",
    "Tester/แถม": "#8a6d9b",
  };
  return (
    <span
      style={{
        background: map[t] || T.faint,
        color: "#fff",
        borderRadius: 5,
        padding: "2px 7px",
        fontSize: 10.5,
        fontWeight: 700,
        whiteSpace: "nowrap",
      }}
    >
      {t}
    </span>
  );
}

/* horizontal ranked bar list, channel-aware colouring */
function RankBars({ rows, colorBy, unit, max }) {
  const mx = max || Math.max(1, ...rows.map((r) => r.v));
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 7 }}>
      {rows.map((r, i) => (
        <div key={i} style={{ display: "flex", alignItems: "center", gap: 9 }}>
          <div
            style={{
              width: colorBy === "channel" ? 116 : 130,
              fontSize: 11.5,
              color: T.ink,
              whiteSpace: "nowrap",
              overflow: "hidden",
              textOverflow: "ellipsis",
              textAlign: "right",
              flexShrink: 0,
            }}
            title={r.n}
          >
            {r.n}
          </div>
          <div
            style={{
              flex: 1,
              background: "#f1f2f4",
              borderRadius: 5,
              height: 18,
              position: "relative",
              overflow: "hidden",
            }}
          >
            <div
              style={{
                position: "absolute",
                inset: 0,
                width: (r.v / mx) * 100 + "%",
                background:
                  colorBy === "channel" ? chColor(r.n) : PAL[i % PAL.length],
                borderRadius: 5,
                transition: "width .3s",
              }}
            />
          </div>
          <div
            style={{
              width: 78,
              fontSize: 11.5,
              fontWeight: 700,
              color: T.ink,
              textAlign: "right",
              flexShrink: 0,
              fontVariantNumeric: "tabular-nums",
            }}
          >
            {fi(r.v)}{" "}
            <span style={{ fontWeight: 400, color: T.faint, fontSize: 10 }}>
              {unit}
            </span>
          </div>
        </div>
      ))}
    </div>
  );
}

/* =========================================================================
   DATA DICTIONARY (footer) — varies per page
   ========================================================================= */
function DataGuide({ items, note }) {
  return (
    <div
      style={{
        background: T.subtle,
        border: "1px dashed " + T.border,
        borderRadius: 12,
        padding: "14px 18px",
        marginTop: 20,
      }}
    >
      <div
        style={{
          fontSize: 12.5,
          fontWeight: 800,
          color: T.ink,
          marginBottom: 8,
          display: "flex",
          alignItems: "center",
          gap: 6,
        }}
      >
        <span>📖</span> คำอธิบายการดูข้อมูลหน้านี้ (Data Dictionary / Page
        Guide)
      </div>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fill,minmax(280px,1fr))",
          gap: "6px 22px",
        }}
      >
        {items.map(([term, desc], i) => (
          <div
            key={i}
            style={{ fontSize: 11.5, color: T.muted, lineHeight: 1.5 }}
          >
            <b style={{ color: T.ink }}>{term}</b> — {desc}
          </div>
        ))}
      </div>
      {note && (
        <div
          style={{
            fontSize: 11,
            color: T.faint,
            marginTop: 9,
            paddingTop: 8,
            borderTop: "1px solid " + T.border,
          }}
        >
          💡 {note}
        </div>
      )}
    </div>
  );
}

/* =========================================================================
   OVERVIEW PAGE
   ========================================================================= */
function Overview({ onPick, range, compare, cmpRange }) {
  const [a, b] = range;
  // aggregate group monthly totals for the mini bar + kpis
  const groupsCalc = useMemo(
    () =>
      D.groups
        .map((g) => {
          const gd = D.g[g.key];
          const rev = sumRange(gd.mtot.rev, a, b);
          const qty = sumRange(gd.mtot.qty, a, b);
          const ord = sumRange(gd.mtot.ord, a, b);
          const crev = cmpRange
            ? sumRange(gd.mtot.rev, cmpRange[0], cmpRange[1])
            : null;
          return { ...g, rev, qty, ord, crev };
        })
        .sort((x, y) => y.rev - x.rev),
    [range, cmpRange]
  );

  const totRev = groupsCalc.reduce((s, g) => s + g.rev, 0);
  const totQty = groupsCalc.reduce((s, g) => s + g.qty, 0);
  const totOrd = groupsCalc.reduce((s, g) => s + g.ord, 0);
  const totSku = D.groups.reduce((s, g) => s + g.skus, 0);
  const cTotRev = cmpRange
    ? groupsCalc.reduce((s, g) => s + (g.crev || 0), 0)
    : null;

  // channel share across all groups (period aware)
  const chAgg = {};
  for (const g of D.groups) {
    for (const e of D.g[g.key].dims.channel) {
      chAgg[e.n] = (chAgg[e.n] || 0) + sumRange(e.mo, a, b);
    }
  }
  const chRows = Object.entries(chAgg)
    .map(([n, v]) => ({ n, v }))
    .sort((x, y) => y.v - x.v);
  const chPie = chRows.map((r) => ({
    name: r.n,
    value: r.v,
    fill: chColor(r.n),
  }));

  const barData = groupsCalc
    .slice(0, 12)
    .map((g) => ({ name: g.name, rev: g.rev }));

  return (
    <>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit,minmax(150px,1fr))",
          gap: 12,
          marginBottom: 16,
        }}
      >
        <Kpi
          label="ยอดขายรวม (บาท)"
          value={fbc(totRev)}
          accent={T.primary}
          delta={<Delta cur={totRev} prev={cTotRev} />}
          sub={fb(totRev)}
        />
        <Kpi
          label="ออเดอร์รวม (ออเดอร์)"
          value={fc(totOrd)}
          accent="#3b6fb0"
          sub={fi(totOrd) + " ออเดอร์"}
        />
        <Kpi
          label="จำนวนขาย (ชิ้น)"
          value={fc(totQty)}
          accent="#b06a2e"
          sub={fi(totQty) + " ชิ้น"}
        />
        <Kpi
          label="SKU ทั้งหมด (รายการ)"
          value={fi(totSku)}
          accent="#7a5aa8"
          sub={D.groups.length + " กลุ่มสินค้า"}
        />
      </div>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1.5fr 1fr",
          gap: 16,
          marginBottom: 16,
        }}
      >
        <Card
          title="ยอดขายตามกลุ่มสินค้า (บาท)"
          hint="Top 12 · ตามช่วงเวลาที่เลือก"
        >
          <ResponsiveContainer width="100%" height={300}>
            <BarChart
              data={barData}
              layout="vertical"
              margin={{ left: 96, right: 16 }}
            >
              <CartesianGrid
                strokeDasharray="3 3"
                stroke="#eef0f2"
                horizontal={false}
              />
              <XAxis
                type="number"
                tickFormatter={fc}
                tick={{ fontSize: 10, fill: T.muted }}
              />
              <YAxis
                type="category"
                dataKey="name"
                tick={{ fontSize: 10.5, fill: T.ink }}
                width={92}
              />
              <Tooltip
                formatter={(v) => fb(v)}
                labelStyle={{ fontSize: 12, fontWeight: 700 }}
                contentStyle={{ fontSize: 12, borderRadius: 8 }}
              />
              <Bar dataKey="rev" radius={[0, 5, 5, 0]}>
                {barData.map((e, i) => (
                  <Cell key={i} fill={PAL[i % PAL.length]} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </Card>
        <Card title="สัดส่วนยอดขายตาม Channel" hint="แยกสีตาม guideline">
          <ResponsiveContainer width="100%" height={220}>
            <PieChart>
              <Pie
                data={chPie}
                dataKey="value"
                nameKey="name"
                cx="50%"
                cy="50%"
                outerRadius={82}
                innerRadius={44}
                paddingAngle={2}
                label={({ percent }) =>
                  percent > 0.06 ? (percent * 100).toFixed(0) + "%" : ""
                }
                labelLine={false}
                style={{ fontSize: 11, fontWeight: 700 }}
              >
                {chPie.map((e, i) => (
                  <Cell key={i} fill={e.fill} />
                ))}
              </Pie>
              <Tooltip
                formatter={(v) => fi(v) + " ออเดอร์"}
                contentStyle={{ fontSize: 12, borderRadius: 8 }}
              />
            </PieChart>
          </ResponsiveContainer>
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              gap: 5,
              marginTop: 6,
            }}
          >
            {chRows.map((r, i) => (
              <div
                key={i}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  fontSize: 11.5,
                }}
              >
                <span
                  style={{
                    width: 11,
                    height: 11,
                    borderRadius: 3,
                    background: chColor(r.n),
                    flexShrink: 0,
                  }}
                />
                <span style={{ color: T.ink, flex: 1 }}>{r.n}</span>
                <span style={{ fontWeight: 700, color: T.ink }}>{fi(r.v)}</span>
                <span style={{ color: T.faint, width: 42, textAlign: "right" }}>
                  {totOrd
                    ? (
                        (r.v / chRows.reduce((s, x) => s + x.v, 0)) *
                        100
                      ).toFixed(1)
                    : 0}
                  %
                </span>
              </div>
            ))}
          </div>
        </Card>
      </div>

      <Card
        title="เลือกกลุ่มสินค้าเพื่อเจาะลึก"
        hint={D.groups.length + " กลุ่ม · เรียงตามยอดขายในช่วงที่เลือก"}
      >
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill,minmax(215px,1fr))",
            gap: 9,
          }}
        >
          {groupsCalc.map((g, i) => (
            <button
              key={g.key}
              onClick={() => onPick(g.key)}
              style={{
                background: T.surface,
                border: "1px solid " + T.border,
                borderRadius: 10,
                padding: "11px 13px",
                cursor: "pointer",
                textAlign: "left",
                borderLeft: "4px solid " + PAL[i % PAL.length],
                transition: "all .12s",
              }}
              onMouseOver={(e) => {
                e.currentTarget.style.background = T.subtle;
                e.currentTarget.style.transform = "translateY(-1px)";
              }}
              onMouseOut={(e) => {
                e.currentTarget.style.background = T.surface;
                e.currentTarget.style.transform = "none";
              }}
            >
              <div style={{ fontSize: 13.5, fontWeight: 700, color: T.ink }}>
                {g.name}
              </div>
              <div style={{ fontSize: 11, color: T.muted, marginTop: 3 }}>
                {g.skus} SKU · {fbc(g.rev)}
              </div>
              <div style={{ fontSize: 10.5, color: T.faint, marginTop: 1 }}>
                {fi(g.ord)} ออเดอร์ · {fi(g.qty)} ชิ้น
              </div>
            </button>
          ))}
        </div>
      </Card>

      <DataGuide
        note="ตัวเลขทั้งหมดคำนวณเฉพาะรายการ 'ขาย' (ไม่รวมของแถม/Tester) และปรับตามช่วงเวลาที่เลือกด้านบน คลิกกลุ่มสินค้าเพื่อดูรายละเอียด SKU และเจาะลึกลูกค้า"
        items={[
          [
            "ยอดขายรวม (บาท)",
            "ผลรวมราคา × จำนวน ของรายการที่เป็นการขายจริงในช่วงเวลาที่เลือก",
          ],
          [
            "ออเดอร์รวม (ออเดอร์)",
            "จำนวนเลขที่ออเดอร์ที่ไม่ซ้ำกัน = จำนวนบิล/ลูกค้าโดยประมาณ",
          ],
          ["จำนวนขาย (ชิ้น)", "ผลรวมจำนวนสินค้าที่ขายออกไป"],
          [
            "สัดส่วน Channel",
            "สัดส่วนออเดอร์แยกตามช่องทาง MarketPlace / Online / Online_คุณอ้อย / ขนมน้องRisa / Telesale",
          ],
          [
            "▲▼ %",
            "อัตราเติบโต/ลดลง เทียบกับช่วงเวลาที่ตั้งไว้ในตัวเลือก 'เทียบกับ'",
          ],
        ]}
      />
    </>
  );
}

/* =========================================================================
   GROUP: SKU TABLE TAB
   ========================================================================= */
function SkuTab({ gkey, range, cmpRange }) {
  const [a, b] = range;
  const gd = D.g[gkey];
  const [sortKey, setSortKey] = useState("qty");
  const [typeFilter, setTypeFilter] = useState("ทั้งหมด");

  const rows = useMemo(() => {
    let r = gd.skus
      .map((s) => {
        const qty = sumRange(s.mq, a, b),
          rev = sumRange(s.mr, a, b),
          ord = sumRange(s.mo, a, b);
        const cqty = cmpRange ? sumRange(s.mq, cmpRange[0], cmpRange[1]) : null;
        return { ...s, qty, rev, ord, cqty };
      })
      .filter((s) => s.qty > 0 || s.rev > 0 || s.ord > 0);
    if (typeFilter !== "ทั้งหมด") r = r.filter((s) => s.type === typeFilter);
    r.sort((x, y) => (y[sortKey] || 0) - (x[sortKey] || 0));
    return r;
  }, [range, cmpRange, sortKey, typeFilter]);

  const types = ["ทั้งหมด", ...Array.from(new Set(gd.skus.map((s) => s.type)))];
  const Th = ({ label, unit, k, w, right }) => (
    <th
      onClick={k ? () => setSortKey(k) : undefined}
      style={{
        padding: "9px 8px",
        textAlign: right ? "right" : "left",
        fontWeight: 700,
        fontSize: 11,
        whiteSpace: "nowrap",
        cursor: k ? "pointer" : "default",
        width: w,
        background: sortKey === k ? T.primaryInk : T.ink,
        color: "#fff",
        position: "sticky",
        top: 0,
      }}
    >
      {label}
      {unit && <span style={{ fontWeight: 400, opacity: 0.8 }}> ({unit})</span>}
      {k && <span style={{ opacity: 0.6 }}>{sortKey === k ? " ▾" : " ⇅"}</span>}
    </th>
  );

  return (
    <>
      <Card pad={0}>
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            padding: "12px 16px",
            flexWrap: "wrap",
          }}
        >
          <h3
            style={{ margin: 0, fontSize: 14, fontWeight: 800, color: T.ink }}
          >
            รายละเอียดทุก SKU
          </h3>
          <span style={{ fontSize: 11, color: T.faint }}>
            เรียงจาก Top performance ({rows.length} SKU ที่มียอดในช่วงที่เลือก)
          </span>
          <div
            style={{
              marginLeft: "auto",
              display: "flex",
              gap: 6,
              alignItems: "center",
            }}
          >
            <span style={{ fontSize: 11, color: T.muted }}>ประเภท:</span>
            <select
              value={typeFilter}
              onChange={(e) => setTypeFilter(e.target.value)}
              style={selStyle}
            >
              {types.map((t) => (
                <option key={t}>{t}</option>
              ))}
            </select>
          </div>
        </div>
        <div style={{ overflowX: "auto" }}>
          <table
            style={{
              width: "100%",
              borderCollapse: "collapse",
              fontSize: 11.5,
              minWidth: 920,
            }}
          >
            <thead>
              <tr>
                <Th label="#" w={34} />
                <Th label="รหัสสินค้า (SKU)" w={170} />
                <Th label="ชื่อสินค้า" w={230} />
                <Th label="ประเภท" w={72} />
                <Th label="ราคาขาย" unit="บาท" w={92} right />
                <Th label="ราคาเฉลี่ย" unit="บาท" k="__" w={96} right />
                <Th label="จำนวนขาย" unit="ชิ้น" k="qty" w={96} right />
                <Th label="ยอดขาย" unit="บาท" k="rev" w={104} right />
                <Th label="ออเดอร์" unit="ออเดอร์" k="ord" w={92} right />
                {cmpRange && <Th label="โต/ลด" unit="%จำนวน" w={78} right />}
              </tr>
            </thead>
            <tbody>
              {rows.map((s, i) => {
                const bg =
                  s.type === "ขาย" || s.type === "Set"
                    ? "#fff"
                    : s.type === "ของแถม"
                    ? "#fffdf5"
                    : "#fdf6f8";
                return (
                  <tr
                    key={s.sku}
                    style={{
                      background: bg,
                      borderBottom: "1px solid #f0f1f3",
                    }}
                  >
                    <td style={{ padding: "7px 8px", color: T.faint }}>
                      {i + 1}
                    </td>
                    <td
                      style={{
                        padding: "7px 8px",
                        fontFamily: "ui-monospace,monospace",
                        fontSize: 10.5,
                        color: T.ink,
                        whiteSpace: "nowrap",
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                        maxWidth: 170,
                      }}
                      title={s.sku}
                    >
                      {s.sku}
                    </td>
                    <td
                      style={{
                        padding: "7px 8px",
                        color: T.muted,
                        maxWidth: 230,
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                        whiteSpace: "nowrap",
                      }}
                      title={s.name}
                    >
                      {s.name}
                    </td>
                    <td style={{ padding: "7px 8px" }}>
                      <TypeBadge t={s.type} />
                    </td>
                    <td
                      style={{
                        padding: "7px 8px",
                        textAlign: "right",
                        color: s.price_sell == null ? T.faint : T.ink,
                        fontWeight: s.price_sell == null ? 400 : 700,
                        fontStyle: s.price_sell == null ? "italic" : "normal",
                      }}
                    >
                      {s.price_sell == null ? "(ไม่ทราบ)" : fi(s.price_sell)}
                    </td>
                    <td
                      style={{
                        padding: "7px 8px",
                        textAlign: "right",
                        color: T.muted,
                        fontVariantNumeric: "tabular-nums",
                      }}
                    >
                      {s.price_avg ? fi(s.price_avg) : "(ไม่ทราบ)"}
                    </td>
                    <td
                      style={{
                        padding: "7px 8px",
                        textAlign: "right",
                        fontWeight: 700,
                        color: T.ink,
                        fontVariantNumeric: "tabular-nums",
                      }}
                    >
                      {fi(s.qty)}
                    </td>
                    <td
                      style={{
                        padding: "7px 8px",
                        textAlign: "right",
                        color: T.ink,
                        fontVariantNumeric: "tabular-nums",
                      }}
                    >
                      {fi(s.rev)}
                    </td>
                    <td
                      style={{
                        padding: "7px 8px",
                        textAlign: "right",
                        color: T.muted,
                        fontVariantNumeric: "tabular-nums",
                      }}
                    >
                      {fi(s.ord)}
                    </td>
                    {cmpRange && (
                      <td style={{ padding: "7px 8px", textAlign: "right" }}>
                        <Delta cur={s.qty} prev={s.cqty} />
                      </td>
                    )}
                  </tr>
                );
              })}
              {rows.length === 0 && (
                <tr>
                  <td
                    colSpan={cmpRange ? 10 : 9}
                    style={{ padding: 24, textAlign: "center", color: T.faint }}
                  >
                    ไม่มี SKU ที่มียอดขายในช่วงเวลานี้
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </Card>

      <DataGuide
        note="คลิกหัวคอลัมน์ (จำนวนขาย / ยอดขาย / ออเดอร์) เพื่อจัดเรียงใหม่ · ตารางแสดงเฉพาะ SKU ที่มีความเคลื่อนไหวในช่วงเวลาที่เลือก · คอลัมน์ 'ราคาขาย' อ้างอิงไฟล์อนุมัติราคาขาย Marketing Retail 2026 — รายการที่ยังไม่พบราคาจะแสดง (ไม่ทราบ)"
        items={[
          [
            "รหัสสินค้า (SKU)",
            "รหัสอ้างอิงสินค้าจริง — prefix N_ = MarketPlace, X_ = Online, T_ = Telesale, C_ = จัดเซ็ต",
          ],
          [
            "ประเภท",
            "ขาย = สินค้าขายเดี่ยว · Set = จัดเซ็ต · ของแถม · Tester = สินค้าตัวอย่าง",
          ],
          [
            "ราคาขาย (บาท)",
            "ราคาขายที่อนุมัติจากไฟล์ราคา 2026 · (ไม่ทราบ) = ยังไม่พบ/ยังไม่ยืนยัน",
          ],
          [
            "ราคาเฉลี่ย (บาท)",
            "ราคาเฉลี่ยจากการขายจริงในข้อมูล 18 เดือน (สะท้อนส่วนลด/โปรฯ)",
          ],
          [
            "จำนวนขาย (ชิ้น)",
            "จำนวนสินค้าที่ขายออกในช่วงเวลาที่เลือก — ตัวชี้วัด Top performance หลัก",
          ],
          ["ยอดขาย (บาท)", "ราคา × จำนวน ในช่วงเวลาที่เลือก"],
          ["ออเดอร์ (ออเดอร์)", "จำนวนบิลที่มี SKU นี้ = ความถี่ที่ลูกค้าซื้อ"],
          [
            "โต/ลด (%จำนวน)",
            "เปลี่ยนแปลงจำนวนขายเทียบช่วงที่ตั้งใน 'เทียบกับ'",
          ],
        ]}
      />
    </>
  );
}

/* =========================================================================
   GROUP: CUSTOMER INSIGHTS TAB
   ========================================================================= */
const PREFIX_LABEL = {
  N_: "N_ (MarketPlace)",
  X_: "X_ (Online)",
  T_: "T_ (Telesale)",
  C_: "C_ (จัดเซ็ต)",
  W: "W (คลังกลาง)",
  อื่นๆ: "อื่นๆ",
};
function skuPrefix(sku) {
  const s = String(sku);
  if (s.startsWith("N_")) return "N_";
  if (s.startsWith("X_")) return "X_";
  if (s.startsWith("T_")) return "T_";
  if (s.startsWith("C_")) return "C_";
  if (s.startsWith("W")) return "W";
  return "อื่นๆ";
}

function CustomerTab({ gkey, range }) {
  const [a, b] = range;
  const gd = D.g[gkey];
  const [f, setF] = useState({
    sku: "",
    prefix: "",
    region: "",
    province: "",
    channel: "",
    page: "",
    team: "",
    sales: "",
    set: "",
    ship: "",
  });
  const set = (k, v) => setF((o) => ({ ...o, [k]: v }));
  const reset = () =>
    setF({
      sku: "",
      prefix: "",
      region: "",
      province: "",
      channel: "",
      page: "",
      team: "",
      sales: "",
      set: "",
      ship: "",
    });

  const dimRows = (dimKey, top) => {
    const arr = (gd.dims[dimKey] || [])
      .map((e) => ({
        n: e.n,
        v: sumRange(e.mo, a, b),
        q: e.mq ? sumRange(e.mq, a, b) : null,
      }))
      .filter((e) => e.v > 0)
      .sort((x, y) => y.v - x.v);
    return top ? arr.slice(0, top) : arr;
  };

  const skuOpts = gd.skus
    .filter((s) => s.type === "ขาย" || s.type === "Set")
    .slice(0, 60);
  const activeSku = f.sku ? gd.sku_cross[f.sku] : null;

  // region / province / channel — switch to per-SKU cross if a SKU is selected (full-period)
  let regionRows,
    provinceRows,
    channelRows,
    crossNote = "";
  if (activeSku) {
    regionRows = Object.entries(activeSku.rg)
      .map(([n, v]) => ({ n, v }))
      .sort((x, y) => y.v - x.v);
    provinceRows = Object.entries(activeSku.pv)
      .map(([n, v]) => ({ n, v }))
      .sort((x, y) => y.v - x.v);
    channelRows = Object.entries(activeSku.ch)
      .map(([n, v]) => ({ n, v }))
      .sort((x, y) => y.v - x.v);
    crossNote = "เจาะ SKU: " + f.sku + " (ข้อมูลรวม 18 เดือน)";
  } else {
    regionRows = dimRows("region");
    provinceRows = dimRows("province", 15);
    channelRows = dimRows("channel");
    // channel filter → region uses channel×region cross
    if (f.channel && gd.cxr[f.channel]) {
      regionRows = Object.entries(gd.cxr[f.channel])
        .map(([n, v]) => ({ n, v }))
        .sort((x, y) => y.v - x.v);
      crossNote = "เจาะ Channel: " + f.channel;
    }
  }
  regionRows = regionRows.filter(
    (r) => r.n !== "ว่างเปล่า" && r.n !== "ไม่ระบุที่อยู่"
  );

  const channelPie = channelRows.map((r) => ({
    name: r.n,
    value: r.v,
    fill: chColor(r.n),
  }));
  const totCh = channelRows.reduce((s, r) => s + r.v, 0);

  // focus panel for secondary filters (team, sales, set, ship, page, province, prefix)
  const focusDim = f.team
    ? ["team", f.team]
    : f.sales
    ? ["salesperson", f.sales]
    : f.set
    ? ["set_code", f.set]
    : f.ship
    ? ["shipping", f.ship]
    : f.page
    ? ["page_shop", f.page]
    : null;
  let focusSeries = null,
    focusRank = null;
  if (focusDim) {
    const e = (gd.dims[focusDim[0]] || []).find((x) => x.n === focusDim[1]);
    if (e) {
      focusSeries = MONTHS.map((m, i) => ({ m: monLabel(m), v: e.mo[i] || 0 }));
    }
    const all = dimRows(focusDim[0]);
    focusRank = all.findIndex((x) => x.n === focusDim[1]) + 1;
  }

  const FSelect = ({ label, k, opts, w }) => (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        gap: 3,
        minWidth: w || 140,
      }}
    >
      <span style={{ fontSize: 10, color: T.muted, fontWeight: 600 }}>
        {label}
      </span>
      <select
        value={f[k]}
        onChange={(e) => set(k, e.target.value)}
        style={{
          ...selStyle,
          maxWidth: "none",
          width: "100%",
          borderColor: f[k] ? T.primary : T.border,
          background: f[k] ? T.primarySoft : T.surface,
          fontWeight: f[k] ? 700 : 400,
        }}
      >
        <option value="">ทั้งหมด</option>
        {opts.map((o, i) => {
          const val = Array.isArray(o) ? o[0] : o;
          const lab = Array.isArray(o) ? o[1] : o;
          return (
            <option key={i} value={val}>
              {typeof lab === "string" && lab.length > 34
                ? lab.slice(0, 34) + "…"
                : lab}
            </option>
          );
        })}
      </select>
    </div>
  );

  return (
    <>
      {/* filter bar */}
      <div
        style={{
          background: T.surface,
          border: "1px solid " + T.border,
          borderRadius: 12,
          padding: "13px 16px",
          marginBottom: 14,
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 8,
            marginBottom: 10,
          }}
        >
          <span style={{ fontSize: 13, fontWeight: 800, color: T.ink }}>
            🔎 ตัวกรองลูกค้า
          </span>
          <span style={{ fontSize: 11, color: T.faint }}>
            เลือก SKU หรือ Channel เพื่อเจาะข้อมูลแบบไขว้ ·
            ตัวกรองอื่นเปิดแผงวิเคราะห์เจาะจง
          </span>
          <button
            onClick={reset}
            style={{
              marginLeft: "auto",
              fontSize: 11,
              padding: "5px 12px",
              borderRadius: 7,
              border: "1px solid " + T.border,
              background: T.surface,
              color: T.muted,
              cursor: "pointer",
              fontWeight: 600,
            }}
          >
            ล้างตัวกรอง
          </button>
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))",
            gap: 9,
          }}
        >
          <FSelect
            label="สินค้า (SKU)"
            k="sku"
            opts={skuOpts.map((s) => [s.sku, s.sku + " · " + s.name])}
          />
          <FSelect
            label="รหัส (prefix)"
            k="prefix"
            opts={Array.from(new Set(gd.skus.map((s) => skuPrefix(s.sku)))).map(
              (p) => [p, PREFIX_LABEL[p] || p]
            )}
          />
          <FSelect
            label="ภาค"
            k="region"
            opts={dimRows("region").map((r) => r.n)}
          />
          <FSelect
            label="จังหวัด"
            k="province"
            opts={dimRows("province", 30).map((r) => r.n)}
          />
          <FSelect
            label="Channel"
            k="channel"
            opts={dimRows("channel").map((r) => r.n)}
          />
          <FSelect
            label="เพจ/ร้าน · ช่องทางติดต่อ"
            k="page"
            opts={dimRows("page_shop", 20).map((r) => r.n)}
          />
          <FSelect
            label="ทีม Telesale"
            k="team"
            opts={dimRows("team").map((r) => r.n)}
          />
          <FSelect
            label="พนักงานขาย"
            k="sales"
            opts={dimRows("salesperson", 20).map((r) => r.n)}
          />
          <FSelect
            label="รหัส SET"
            k="set"
            opts={dimRows("set_code").map((r) => r.n)}
          />
          <FSelect
            label="ขนส่ง"
            k="ship"
            opts={dimRows("shipping", 15).map((r) => r.n)}
          />
        </div>
        {crossNote && (
          <div
            style={{
              marginTop: 10,
              fontSize: 11.5,
              color: T.primaryInk,
              background: T.primarySoft,
              borderRadius: 7,
              padding: "6px 11px",
              display: "inline-block",
              fontWeight: 700,
            }}
          >
            ▸ {crossNote}
          </div>
        )}
      </div>

      {/* focus panel */}
      {focusDim && focusSeries && (
        <Card
          title={"แนวโน้มเจาะจง: " + focusDim[1]}
          hint={
            "อันดับ " +
            focusRank +
            " ในมิติ " +
            {
              team: "ทีม",
              salesperson: "พนักงานขาย",
              set_code: "รหัส SET",
              shipping: "ขนส่ง",
              page_shop: "เพจ/ร้าน",
            }[focusDim[0]]
          }
        >
          <ResponsiveContainer width="100%" height={180}>
            <AreaChart data={focusSeries} margin={{ left: -18, right: 8 }}>
              <defs>
                <linearGradient id="fg" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor={T.primary} stopOpacity={0.35} />
                  <stop offset="100%" stopColor={T.primary} stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#eef0f2" />
              <XAxis dataKey="m" tick={{ fontSize: 9, fill: T.muted }} />
              <YAxis tick={{ fontSize: 9, fill: T.muted }} tickFormatter={fc} />
              <Tooltip
                formatter={(v) => fi(v) + " ออเดอร์"}
                contentStyle={{ fontSize: 12, borderRadius: 8 }}
              />
              <Area
                type="monotone"
                dataKey="v"
                stroke={T.primary}
                strokeWidth={2}
                fill="url(#fg)"
              />
            </AreaChart>
          </ResponsiveContainer>
        </Card>
      )}

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: 14,
          marginTop: 14,
          marginBottom: 14,
        }}
      >
        {/* channel — colour coded */}
        <Card title="ตาม Channel" hint="แยกสีตาม guideline (ออเดอร์)">
          <div style={{ display: "flex", gap: 14, alignItems: "center" }}>
            <ResponsiveContainer width="45%" height={170}>
              <PieChart>
                <Pie
                  data={channelPie}
                  dataKey="value"
                  nameKey="name"
                  cx="50%"
                  cy="50%"
                  outerRadius={70}
                  innerRadius={38}
                  paddingAngle={2}
                  label={({ percent }) =>
                    percent > 0.08 ? (percent * 100).toFixed(0) + "%" : ""
                  }
                  labelLine={false}
                  style={{ fontSize: 10, fontWeight: 700 }}
                >
                  {channelPie.map((e, i) => (
                    <Cell key={i} fill={e.fill} />
                  ))}
                </Pie>
                <Tooltip
                  formatter={(v) => fi(v) + " ออเดอร์"}
                  contentStyle={{ fontSize: 12, borderRadius: 8 }}
                />
              </PieChart>
            </ResponsiveContainer>
            <div
              style={{
                flex: 1,
                display: "flex",
                flexDirection: "column",
                gap: 6,
              }}
            >
              {channelRows.map((r, i) => (
                <div
                  key={i}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 8,
                    fontSize: 11.5,
                  }}
                >
                  <span
                    style={{
                      width: 11,
                      height: 11,
                      borderRadius: 3,
                      background: chColor(r.n),
                      flexShrink: 0,
                    }}
                  />
                  <span
                    style={{
                      color: T.ink,
                      flex: 1,
                      whiteSpace: "nowrap",
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                    }}
                  >
                    {r.n}
                  </span>
                  <span
                    style={{
                      fontWeight: 700,
                      color: T.ink,
                      fontVariantNumeric: "tabular-nums",
                    }}
                  >
                    {fi(r.v)}
                  </span>
                  <span
                    style={{ color: T.faint, width: 40, textAlign: "right" }}
                  >
                    {totCh ? ((r.v / totCh) * 100).toFixed(1) : 0}%
                  </span>
                </div>
              ))}
            </div>
          </div>
        </Card>
        {/* region */}
        <Card title="ตามภาค" hint={activeSku ? "เจาะ SKU" : "ออเดอร์"}>
          <RankBars rows={regionRows.slice(0, 8)} unit="ออเดอร์" />
        </Card>
      </div>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: 14,
          marginBottom: 14,
        }}
      >
        <Card
          title="จังหวัดยอดนิยม"
          hint={(activeSku ? "เจาะ SKU · " : "") + "Top 15 (ออเดอร์)"}
        >
          <RankBars rows={provinceRows.slice(0, 15)} unit="ออเดอร์" />
        </Card>
        <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
          <Card title="เพจ / ร้าน · ช่องทางติดต่อ" hint="Top 8 (ออเดอร์)">
            <RankBars rows={dimRows("page_shop", 8)} unit="ออเดอร์" />
          </Card>
          <Card title="รหัส SET" hint="ออเดอร์">
            <RankBars rows={dimRows("set_code", 7)} unit="ออเดอร์" />
          </Card>
        </div>
      </div>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr 1fr",
          gap: 14,
          marginBottom: 4,
        }}
      >
        <Card title="ทีม Telesale" hint="ออเดอร์">
          <RankBars rows={dimRows("team", 8)} unit="ออเดอร์" />
        </Card>
        <Card title="พนักงานขาย" hint="Top 10 (ออเดอร์)">
          <RankBars rows={dimRows("salesperson", 10)} unit="ออเดอร์" />
        </Card>
        <Card title="ขนส่ง" hint="Top 10 (ออเดอร์)">
          <RankBars rows={dimRows("shipping", 10)} unit="ออเดอร์" />
        </Card>
      </div>

      <DataGuide
        note="การเลือก 'สินค้า (SKU)' จะสลับการ์ด ภาค/จังหวัด/Channel ให้แสดงเฉพาะ SKU นั้น (ข้อมูลรวม 18 เดือน) · การเลือก 'Channel' จะเจาะภาคของช่องทางนั้น · การเลือกทีม/พนักงาน/SET/ขนส่ง/เพจ จะเปิดแผงแนวโน้มเจาะจงด้านบน · การ์ดทั่วไปปรับตามช่วงเวลาที่เลือก"
        items={[
          [
            "ภาค / จังหวัด",
            "ที่อยู่ลูกค้าจากรหัสไปรษณีย์ — ใช้ดูว่าสินค้าขายดีในพื้นที่ใด เพื่อวางแผนโฆษณาแบบ geo-targeting",
          ],
          [
            "Channel (แยกสี)",
            "ช่องทางขายหลัก 5 กลุ่มตามสีมาตรฐาน — ชมพู MarketPlace, ส้ม Online, ม่วง Online_คุณอ้อย, เขียว ขนมน้องRisa, น้ำเงิน Telesale",
          ],
          [
            "เพจ/ร้าน · ช่องทางติดต่อ",
            "เพจ Facebook / ร้าน Shopee-Lazada-TikTok / Line ที่ลูกค้าติดต่อเข้ามา — ใช้วัดว่าโฆษณาช่องไหนได้ผล",
          ],
          [
            "ทีม Telesale",
            "ทีมผู้ดูแลออเดอร์ (M1–M4 / Call Center / สำนักงานใหญ่)",
          ],
          ["พนักงานขาย", "บัญชีผู้สร้างออเดอร์ — ใช้ดู performance รายบุคคล"],
          [
            "รหัส SET",
            "รูปแบบชุดโปรโมชั่นที่ลูกค้าซื้อ (SET0–SET6) — ใช้ดูว่าเซ็ตไหนขายดี",
          ],
          [
            "ขนส่ง",
            "บริษัทขนส่งที่ใช้ส่ง — ช่วยดูสัดส่วน COD และต้นทุนโลจิสติกส์",
          ],
          ["ออเดอร์", "จำนวนบิลไม่ซ้ำ = จำนวนลูกค้าโดยประมาณในแต่ละมิติ"],
        ]}
      />
    </>
  );
}

/* =========================================================================
   GROUP: OVERVIEW TAB
   ========================================================================= */
function GroupOverview({ gkey, range, cmpRange, compare }) {
  const [a, b] = range;
  const gd = D.g[gkey];
  const rev = sumRange(gd.mtot.rev, a, b),
    qty = sumRange(gd.mtot.qty, a, b),
    ord = sumRange(gd.mtot.ord, a, b);
  const crev = cmpRange
    ? sumRange(gd.mtot.rev, cmpRange[0], cmpRange[1])
    : null;
  const cqty = cmpRange
    ? sumRange(gd.mtot.qty, cmpRange[0], cmpRange[1])
    : null;
  const cord = cmpRange
    ? sumRange(gd.mtot.ord, cmpRange[0], cmpRange[1])
    : null;
  const aov = ord ? rev / ord : 0;
  const trend = MONTHS.map((m, i) => ({
    m: monLabel(m),
    qty: gd.mtot.qty[i] || 0,
    ord: gd.mtot.ord[i] || 0,
    sel: i >= a && i <= b,
  }));

  const chRows = (gd.dims.channel || [])
    .map((e) => ({ n: e.n, v: sumRange(e.mo, a, b) }))
    .filter((e) => e.v > 0)
    .sort((x, y) => y.v - x.v);
  const regionRows = (gd.dims.region || [])
    .map((e) => ({ n: e.n, v: sumRange(e.mo, a, b) }))
    .filter((e) => e.v > 0 && e.n !== "ว่างเปล่า" && e.n !== "ไม่ระบุที่อยู่")
    .sort((x, y) => y.v - x.v)
    .slice(0, 8);
  const totCh = chRows.reduce((s, r) => s + r.v, 0);

  return (
    <>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit,minmax(150px,1fr))",
          gap: 12,
          marginBottom: 16,
        }}
      >
        <Kpi
          label="ยอดขาย (บาท)"
          value={fbc(rev)}
          accent={T.primary}
          delta={<Delta cur={rev} prev={crev} />}
          sub={fb(rev)}
        />
        <Kpi
          label="ออเดอร์ (ออเดอร์)"
          value={fc(ord)}
          accent="#3b6fb0"
          delta={<Delta cur={ord} prev={cord} />}
          sub={fi(ord) + " บิล"}
        />
        <Kpi
          label="จำนวนขาย (ชิ้น)"
          value={fc(qty)}
          accent="#b06a2e"
          delta={<Delta cur={qty} prev={cqty} />}
          sub={fi(qty) + " ชิ้น"}
        />
        <Kpi
          label="มูลค่าต่อออเดอร์ (บาท/ออเดอร์)"
          value={fb(aov)}
          accent="#7a5aa8"
          sub="AOV"
        />
      </div>

      <Card title="แนวโน้มรายเดือน" hint="แท่งเข้ม = อยู่ในช่วงที่เลือก">
        <ResponsiveContainer width="100%" height={260}>
          <LineChart data={trend} margin={{ left: -10, right: 10 }}>
            <CartesianGrid strokeDasharray="3 3" stroke="#eef0f2" />
            <XAxis dataKey="m" tick={{ fontSize: 10, fill: T.muted }} />
            <YAxis
              yAxisId="l"
              tick={{ fontSize: 10, fill: T.muted }}
              tickFormatter={fc}
            />
            <YAxis
              yAxisId="r"
              orientation="right"
              tick={{ fontSize: 10, fill: T.muted }}
              tickFormatter={fc}
            />
            <Tooltip contentStyle={{ fontSize: 12, borderRadius: 8 }} />
            <Legend wrapperStyle={{ fontSize: 11 }} />
            <Line
              yAxisId="l"
              type="monotone"
              dataKey="qty"
              name="จำนวนขาย (ชิ้น)"
              stroke={T.primary}
              strokeWidth={2.5}
              dot={false}
            />
            <Line
              yAxisId="r"
              type="monotone"
              dataKey="ord"
              name="ออเดอร์"
              stroke="#b06a2e"
              strokeWidth={2}
              dot={false}
              strokeDasharray="4 3"
            />
          </LineChart>
        </ResponsiveContainer>
      </Card>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: 14,
          marginTop: 14,
        }}
      >
        <Card title="สัดส่วน Channel" hint="แยกสีตาม guideline">
          <div style={{ display: "flex", flexDirection: "column", gap: 7 }}>
            {chRows.map((r, i) => (
              <div key={i}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    fontSize: 11.5,
                    marginBottom: 2,
                  }}
                >
                  <span style={{ color: T.ink, fontWeight: 600 }}>{r.n}</span>
                  <span style={{ color: T.muted }}>
                    {fi(r.v)} · {totCh ? ((r.v / totCh) * 100).toFixed(1) : 0}%
                  </span>
                </div>
                <div
                  style={{
                    background: "#f1f2f4",
                    borderRadius: 5,
                    height: 14,
                    overflow: "hidden",
                  }}
                >
                  <div
                    style={{
                      height: "100%",
                      width: (totCh ? (r.v / totCh) * 100 : 0) + "%",
                      background: chColor(r.n),
                      borderRadius: 5,
                    }}
                  />
                </div>
              </div>
            ))}
          </div>
        </Card>
        <Card title="ยอดขายตามภาค" hint="ออเดอร์">
          <RankBars rows={regionRows} unit="ออเดอร์" />
        </Card>
      </div>

      <DataGuide
        note="หน้านี้สรุปภาพรวมของกลุ่มสินค้าตามช่วงเวลาที่เลือก ไปที่แท็บ 'รายละเอียด SKU' เพื่อดูรายสินค้า และ 'เจาะลึกลูกค้า' เพื่อวิเคราะห์พื้นที่/ช่องทาง"
        items={[
          [
            "ยอดขาย / ออเดอร์ / จำนวนขาย",
            "ตัวชี้วัดหลักของกลุ่ม ปรับตามช่วงเวลา พร้อม ▲▼ เทียบช่วงก่อนหน้า/ปีก่อน",
          ],
          [
            "มูลค่าต่อออเดอร์ (AOV)",
            "ยอดขาย ÷ ออเดอร์ = ลูกค้าจ่ายเฉลี่ยต่อบิล ยิ่งสูงยิ่งขายพ่วง/เซ็ตได้ดี",
          ],
          [
            "แนวโน้มรายเดือน",
            "เส้นทึบ=จำนวนชิ้น เส้นประ=ออเดอร์ ใช้ดู seasonality และผลของแคมเปญ",
          ],
          ["Channel (แยกสี)", "สัดส่วนช่องทางขาย ใช้สีมาตรฐานเพื่อจดจำง่าย"],
          ["ภาค", "ภูมิภาคที่ลูกค้าอยู่ ใช้เลือกพื้นที่ยิงโฆษณา"],
        ]}
      />
    </>
  );
}

/* =========================================================================
   ROOT
   ========================================================================= */
export default function App() {
  const [gkey, setGkey] = useState(null);
  const [range, setRange] = useState([0, 17]);
  const [compare, setCompare] = useState("none");
  const [tab, setTab] = useState("overview");

  const [a, b] = range;
  const len = b - a + 1;
  const cmpRange = useMemo(() => {
    if (compare === "none") return null;
    if (compare === "prev") {
      const pa = a - len,
        pb = a - 1;
      return pa >= 0 ? [pa, pb] : null;
    }
    if (compare === "yoy") {
      const pa = a - 12,
        pb = b - 12;
      return pa >= 0 ? [pa, pb] : null;
    }
    return null;
  }, [compare, a, b]);

  // metric for period-bar mini chart (group orders if in group, else all-group orders)
  const metricObj = useMemo(() => {
    if (gkey) return D.g[gkey].mtot.ord;
    const agg = {};
    for (const g of D.groups) {
      const o = D.g[g.key].mtot.ord;
      for (const k in o) agg[k] = (agg[k] || 0) + o[k];
    }
    return agg;
  }, [gkey]);

  const gInfo = gkey ? D.groups.find((g) => g.key === gkey) : null;

  return (
    <div
      style={{
        fontFamily:
          "'Sarabun','IBM Plex Sans Thai','Inter',system-ui,sans-serif",
        background: T.canvas,
        minHeight: "100vh",
      }}
    >
      {/* app bar */}
      <div style={{ background: T.ink, color: "#fff", padding: "16px 22px" }}>
        <div
          style={{
            maxWidth: 1240,
            margin: "0 auto",
            display: "flex",
            alignItems: "center",
            gap: 12,
          }}
        >
          <div
            style={{
              width: 34,
              height: 34,
              borderRadius: 9,
              background: T.primary,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontWeight: 800,
              fontSize: 16,
            }}
          >
            W
          </div>
          <div>
            <div
              style={{ fontSize: 17, fontWeight: 800, letterSpacing: "-.3px" }}
            >
              Wellgate · Product Analytics
            </div>
            <div style={{ fontSize: 11.5, opacity: 0.6 }}>
              แดชบอร์ดวิเคราะห์สินค้าเชิงลึกสำหรับทีม Marketing · ข้อมูล 18
              เดือน (ม.ค. 2025 – มิ.ย. 2026)
            </div>
          </div>
        </div>
      </div>

      <div
        style={{ maxWidth: 1240, margin: "0 auto", padding: "18px 22px 40px" }}
      >
        {/* breadcrumb / back */}
        {gkey && (
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 12,
              marginBottom: 14,
              flexWrap: "wrap",
            }}
          >
            <button
              onClick={() => {
                setGkey(null);
                setTab("overview");
              }}
              style={{
                fontSize: 12.5,
                padding: "6px 14px",
                borderRadius: 8,
                border: "1px solid " + T.border,
                background: T.surface,
                color: T.muted,
                cursor: "pointer",
                fontWeight: 600,
              }}
            >
              ← ทุกกลุ่มสินค้า
            </button>
            <h2
              style={{ margin: 0, fontSize: 19, fontWeight: 800, color: T.ink }}
            >
              {gInfo.name}
            </h2>
            <span style={{ fontSize: 12, color: T.faint }}>
              {gInfo.skus} SKU
            </span>
            <div
              style={{
                marginLeft: "auto",
                display: "flex",
                gap: 6,
                background: T.surface,
                border: "1px solid " + T.border,
                borderRadius: 9,
                padding: 4,
              }}
            >
              {[
                ["overview", "ภาพรวมกลุ่ม"],
                ["sku", "รายละเอียด SKU"],
                ["customer", "เจาะลึกลูกค้า"],
              ].map(([v, l]) => (
                <button
                  key={v}
                  onClick={() => setTab(v)}
                  style={{
                    fontSize: 12.5,
                    padding: "6px 14px",
                    borderRadius: 7,
                    border: "none",
                    cursor: "pointer",
                    fontWeight: 700,
                    background: tab === v ? T.ink : "transparent",
                    color: tab === v ? "#fff" : T.muted,
                  }}
                >
                  {l}
                </button>
              ))}
            </div>
          </div>
        )}

        <PeriodBar
          range={range}
          setRange={setRange}
          compare={compare}
          setCompare={setCompare}
          metricObj={metricObj}
          cmpRange={cmpRange}
        />

        {!gkey && (
          <Overview
            onPick={setGkey}
            range={range}
            compare={compare}
            cmpRange={cmpRange}
          />
        )}
        {gkey && tab === "overview" && (
          <GroupOverview
            gkey={gkey}
            range={range}
            cmpRange={cmpRange}
            compare={compare}
          />
        )}
        {gkey && tab === "sku" && (
          <SkuTab gkey={gkey} range={range} cmpRange={cmpRange} />
        )}
        {gkey && tab === "customer" && (
          <CustomerTab gkey={gkey} range={range} />
        )}

        <div
          style={{
            textAlign: "center",
            fontSize: 10.5,
            color: T.faint,
            marginTop: 22,
          }}
        >
          Wellgate Distribution · ข้อมูล 385,508 รายการ · 18 เดือน ·{" "}
          {D.groups.length} กลุ่มสินค้า ·{" "}
          {D.groups.reduce((s, g) => s + g.skus, 0)} SKU
        </div>
      </div>
    </div>
  );
}
